Errors by Status Code

viewof selectedSubdomain = Inputs.select(["All", ...subdomains], {label: "Subdomain", value: "All"})







filtered = selectedSubdomain === "All" ? summary : summary.filter(d =&gt; d.subdomain === selectedSubdomain)

// Aggregate by status code across selected subdomains
statusAgg = Array.from(
  d3.rollup(filtered, v =&gt; d3.sum(v, d =&gt; d.count), d =&gt; d.status_code),
  ([status_code, count]) =&gt; ({status_code: String(status_code), count})
)

Plot.plot({
  height: 350,
  marginLeft: 60,
  marginRight: 80,
  x: {label: "Error Count"},
  y: {label: "Status Code"},
  marks: [
    Plot.barX(statusAgg, {
      y: "status_code",
      x: "count",
      fill: "status_code",
      sort: {y: "-x"}
    }),
    Plot.text(statusAgg, {
      y: "status_code",
      x: "count",
      text: d =&gt; d.count.toLocaleString(),
      dx: 5,
      textAnchor: "start"
    }),
    Plot.ruleX([0])
  ]
})

