Top Failing Endpoints

filteredUrls = selectedSubdomain === "All" ? urls : urls.filter(d =&gt; d.subdomain === selectedSubdomain)
topUrls = filteredUrls.sort((a, b) =&gt; b.count - a.count).slice(0, 25)

// Shorten URLs for display
shortenUrl = (url) =&gt; {
  try {
    const u = new URL(url)
    return u.pathname
  } catch {
    return url.length &gt; 80 ? url.slice(0, 77) + "..." : url
  }
}

Plot.plot({
  height: Math.max(400, topUrls.length * 28),
  marginLeft: 400,
  marginRight: 80,
  x: {label: "Error Count"},
  y: {label: null},
  marks: [
    Plot.barX(topUrls, {
      y: d =&gt; shortenUrl(d.url),
      x: "count",
      fill: "subdomain",
      sort: {y: "-x"}
    }),
    Plot.text(topUrls, {
      y: d =&gt; shortenUrl(d.url),
      x: "count",
      text: d =&gt; d.count.toLocaleString(),
      dx: 5,
      textAnchor: "start"
    }),
    Plot.ruleX([0])
  ]
})

